async (page) => {
  const asciiMap = await page.evaluate(() => {
    const m = window.__latestAsciiMap;
    return m && !m.error ? (m.ascii + '\n\n' + m.legendText) : JSON.stringify(m);
  });
  return asciiMap;
}

async (page) => {
  // Navigate north through narrow corridor at x=200-201
  const result = await page.evaluate(({x, y}) => JSON.stringify(window.__clickTile(x, y)), {x: 200, y: 136});
  await page.waitForTimeout(4000);
  const pos = await page.evaluate(() => window.__latestGameState.player_position);
  return JSON.stringify(pos);
}

async (page) => {
  const r = await page.evaluate(({x, y}) => JSON.stringify(window.__clickTile(x, y)), {x: 216, y: 114});
  await page.waitForTimeout(4000);
  const state = await page.evaluate(() => {
    const s = window.__latestGameState;
    return { pos: s.player_position, hp: s.player_stats.hp, nearby: (s.nearby_entities||[]).slice(0,8).map(e=>({name:e.name,type:e.type,id:e.id,dist:e.distance,on_screen:e.on_screen,quest_npc:e.quest_npc})) };
  });
  return JSON.stringify(state);
}
